import { supabase } from "./supabase";

const GMT8_OFFSET_MINUTES = 8 * 60;
const MINUTE_MS = 60 * 1000;

type FiveMinuteRow = {
  timestamp: string;
  battery_level?: number | string | null;
  battery_status?: string | null;
  production_kwh?: number | string | null;
  consumption_kwh?: number | string | null;
  grid_import_kwh?: number | string | null;
  grid_export_kwh?: number | string | null;
  daily_earning?: number | string | null;
  lifetime_earning?: number | string | null;
  lifetime_savings_php?: number | string | null;
  lifetime_earning_php?: number | string | null;
  lifetime_earnings_php?: number | string | null;
  [key: string]: unknown;
};

export type LiveData = {
  current_power_w: number;
  today_production_kwh: number;
  today_consumption_kwh: number;
  today_grid_import_kwh: number;
  today_grid_export_kwh: number;
  battery_level: number | null;
  battery_status: string | null;
  capacity_kwp: number;
  station_name: string;
  lifetime_earning?: number;
  month_production_kwh: number;
  today_hourly?: {
    hour: number;
    production_kwh: number;
    consumption_kwh: number;
  }[];
  today_readings?: {
    timestamp: string;
    production_kwh: number;
    consumption_kwh: number;
    battery_level: number | null;
  }[];
};

export type HomeLiveData = Pick<
  LiveData,
  "battery_level" | "battery_status" | "lifetime_earning"
>;

const normalizeDateInput = (value: string | Date): Date =>
  value instanceof Date ? value : new Date(value);

const toGmt8WallClock = (date: Date): Date =>
  new Date(date.getTime() + GMT8_OFFSET_MINUTES * MINUTE_MS);

const getGmt8Parts = (value: string | Date) => {
  const wallClock = toGmt8WallClock(normalizeDateInput(value));
  return {
    year: wallClock.getUTCFullYear(),
    month: wallClock.getUTCMonth(),
    day: wallClock.getUTCDate(),
    hour: wallClock.getUTCHours(),
  };
};

const getStartOfGmt8Day = (value: string | Date): Date => {
  const { year, month, day } = getGmt8Parts(value);
  return new Date(Date.UTC(year, month, day) - GMT8_OFFSET_MINUTES * MINUTE_MS);
};

const round = (value: number, decimals = 1) => {
  const factor = 10 ** decimals;
  return Math.round(value * factor) / factor;
};

const toNumber = (...values: unknown[]): number => {
  for (const value of values) {
    if (value == null) continue;
    const parsed = Number(value);
    if (!Number.isNaN(parsed)) return parsed;
  }
  return 0;
};

const sumBy = (rows: FiveMinuteRow[], getter: (row: FiveMinuteRow) => number) =>
  rows.reduce((sum, row) => sum + getter(row), 0);

const getCurrentUser = async () => {
  const {
    data: { user },
  } = await supabase.auth.getUser();
  return user;
};





export const fetchHomeLiveData = async (): Promise<HomeLiveData | null> => {
  try {
    const user = await getCurrentUser();
    if (!user) {
      console.log("fetchHomeLiveData: no active user");
      return null;
    }

    const [latestResult, lifetimeResult] = await Promise.all([
      supabase
        .from("energy_readings_five_minutes")
        .select("battery_level,battery_status,lifetime_earning,timestamp")
        .eq("user_id", user.id)
        .order("timestamp", { ascending: false })
        .limit(1)
        .maybeSingle(),
      supabase
        .from("energy_readings_five_minutes")
        .select("lifetime_earning")
        .eq("user_id", user.id)
        .order("timestamp", { ascending: false })
        .limit(1)
        .maybeSingle(),
    ]);

    if (latestResult.error) {
      console.log("fetchHomeLiveData latest error:", latestResult.error.message);
      return null;
    }

    if (lifetimeResult.error) {
      console.log("fetchHomeLiveData lifetime error:", lifetimeResult.error.message);
      return null;
    }

        // ADDED LOGS HERE:
    console.log("--- fetchHomeLiveData LOGS ---");
    console.log("latestRow returned:", latestResult);
    console.log("user.id:", user.id);
    console.log("lifetimeRow returned:", lifetimeResult);
    console.log("------------------------------");

    const latestRow = (latestResult.data ?? null) as FiveMinuteRow | null;

    const lifetimeRow = (lifetimeResult.data ?? null) as FiveMinuteRow | null;


    return {
      battery_level:
        latestRow?.battery_level == null
          ? null
          : toNumber(latestRow.battery_level),
      battery_status:
        typeof latestRow?.battery_status === "string"
          ? latestRow.battery_status
          : null,
      lifetime_earning: latestRow?.lifetime_earning ? toNumber(latestRow.lifetime_earning) : undefined,
    };
  } catch (error) {
    console.log("fetchHomeLiveData error:", error);
    return null;
  }
};

export const fetchTodayLiveData = async (): Promise<LiveData | null> => {
  try {
    const user = await getCurrentUser();
    if (!user) {
      console.log("fetchTodayLiveData: no active user");
      return null;
    }

    const todayStart = getStartOfGmt8Day(new Date()).toISOString();
    console.log("fetchTodayLiveData debug | user.id:", user.id, "todayStart:", todayStart);

    const [todayResult, latestResult] = await Promise.all([
      supabase
        .from("energy_readings_five_minutes")
        .select("timestamp,production_kwh,consumption_kwh,battery_level,grid_import_kwh,grid_export_kwh")
        .eq("user_id", user.id)
        .gte("timestamp", todayStart)
        .order("timestamp", { ascending: true }),
      supabase
        .from("energy_readings_five_minutes")
        .select("timestamp,production_kwh,battery_level,battery_status")
        .eq("user_id", user.id)
        .order("timestamp", { ascending: false })
        .limit(1)
        .maybeSingle(),
    ]);

    if (todayResult.error) {
      console.log("fetchTodayLiveData today error:", todayResult.error.message);
      return null;
    }

    if (latestResult.error) {
      console.log("fetchTodayLiveData latest error:", latestResult.error.message);
      return null;
    }

    const todayRows = (todayResult.data ?? []) as FiveMinuteRow[];
    const latestRow = (latestResult.data ?? null) as FiveMinuteRow | null;
    console.log("fetchTodayLiveData debug | todayRows count:", todayRows.length, "first row:", todayRows[0]);

    const todayProduction = sumBy(todayRows, (row) =>
      toNumber(row.production_kwh),
    );
    const todayConsumption = sumBy(todayRows, (row) =>
      toNumber(row.consumption_kwh),
    );
    const todayGridImport = sumBy(todayRows, (row) => toNumber(row.grid_import_kwh));
    const todayGridExport = sumBy(todayRows, (row) => toNumber(row.grid_export_kwh));

    const todayHourlyMap = new Map<
      number,
      { production_kwh: number; consumption_kwh: number }
    >();

    todayRows.forEach((row) => {
      const hour = getGmt8Parts(row.timestamp).hour;
      const current = todayHourlyMap.get(hour) ?? {
        production_kwh: 0,
        consumption_kwh: 0,
      };
      current.production_kwh += toNumber(row.production_kwh);
      current.consumption_kwh += toNumber(row.consumption_kwh);
      todayHourlyMap.set(hour, current);
    });

    const todayHourly = Array.from(todayHourlyMap.entries())
      .sort(([a], [b]) => a - b)
      .map(([hour, values]) => ({
        hour,
        production_kwh: round(values.production_kwh, 3),
        consumption_kwh: round(values.consumption_kwh, 3),
      }));

    const todayReadings = todayRows.map((row) => ({
      timestamp: row.timestamp,
      production_kwh: round(toNumber(row.production_kwh), 3),
      consumption_kwh: round(toNumber(row.consumption_kwh), 3),
      battery_level:
        row.battery_level == null ? null : toNumber(row.battery_level),
    }));

    return {
      current_power_w: 0,
      today_production_kwh: round(todayProduction, 3),
      today_consumption_kwh: round(todayConsumption, 3),
      today_grid_import_kwh: round(todayGridImport, 3),
      today_grid_export_kwh: round(todayGridExport, 3),
      battery_level:
        latestRow?.battery_level == null
          ? null
          : toNumber(latestRow.battery_level),
      battery_status:
        typeof latestRow?.battery_status === "string"
          ? latestRow.battery_status
          : null,
      capacity_kwp: 0,
      station_name: "Solar System",
      lifetime_savings_php: undefined,
      month_production_kwh: 0,
      today_hourly: todayHourly,
      today_readings: todayReadings,
    };
  } catch (error) {
    console.log("fetchTodayLiveData error:", error);
    return null;
  }
};

export const fetchLiveData = async (): Promise<LiveData | null> => {
  try {
    const [todayData, homeData] = await Promise.all([
      fetchTodayLiveData(),
      fetchHomeLiveData(),
    ]);

    if (!todayData) {
      return null;
    }

    return {
      ...todayData,
      battery_level: homeData?.battery_level ?? todayData.battery_level,
      battery_status: homeData?.battery_status ?? todayData.battery_status,
      lifetime_earning: homeData?.lifetime_earning,
      month_production_kwh: 0,
    };
  } catch (error) {
    console.log("fetchLiveData error:", error);
    return null;
  }
};
